const XSS_PATTERNS=[/^javascript:/i,/^data:/i,/^vbscript:/i,/^file:/i,/</,/\bon\w+\s*=/i,/&#/i,/%3C/i,/\\x/i,/alert\(/i,/<script/i],FUNNY_MSGS=["Nice try, hacker boy. \u{1F468}\u200D\u{1F4BB}","\u{1F6A8} Caught you being sneaky! Real URL only.","Sir, this is a Wendy's. Use http:// or https://","Error 418: I'm a teapot. Also that's not a valid URL.","Is that XSS in your pocket or just happy to see me?","You're not slick. HTTP only, pal.","Plot twist: that URL isn't real. Try again.","Haha, very funny. Now try a real URL.","We've seen this trick before. Pick a real URL.","That URL is more fake than a $3 bill."];export function pickFunnyMsg(){return FUNNY_MSGS[Math.floor(Math.random()*FUNNY_MSGS.length)]}export function validateBaseUrl(url){if(!url)return{valid:!1,xss:!1,sanitized:"",error:""};for(const pattern of XSS_PATTERNS)if(pattern.test(url.trim()))return{valid:!1,xss:!0,sanitized:"",error:pickFunnyMsg()};try{const parsed=new URL(url.trim());return parsed.protocol!=="http:"&&parsed.protocol!=="https:"?{valid:!1,xss:!1,sanitized:"",error:"Use http:// or https:// protocol"}:{valid:!0,xss:!1,sanitized:parsed.toString(),error:""}}catch{return{valid:!1,xss:!1,sanitized:"",error:"Invalid URL \u2014 did you forget https://?"}}}export function sanitizeBaseUrl(url){if(!url)return"";try{const parsed=new URL(url.trim());return parsed.protocol!=="http:"&&parsed.protocol!=="https:"?"":parsed.toString()}catch{return""}}
